1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_SIZE = 3;
4	const BLOCK_PREMIUM = 60;
5	
6	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	const isComponent = (item: any): boolean => !(item.type in MAIN_ITEM_PREMIUMS);
14	
15	const countComponentsByType = (items: any[]): Record<string, number> => {
16	  const counts: Record<string, number> = {};
17	  for (const item of items) {
18	    if (isComponent(item)) {
19	      counts[item.type] = (counts[item.type] ?? 0) + 1;
20	    }
21	  }
22	  return counts;
23	};
24	
25	const calculateComponentPremium = (count: number): number =>
26	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
27	
28	const calculateMainItemPremium = (item: any): number => {
29	  const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
30	  const curseSurcharge = item.cursed ? base * 0.5 : 0;
31	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
32	  return base + curseSurcharge + enchantmentSurcharge;
33	};
34	
35	const calculateQuotePremium = (items: any[], customer: any, isFollowUp: boolean): number => {
36	  const mainItems = items.filter((item: any) => !isComponent(item));
37	
38	  const policyBasePremium = mainItems
39	    .reduce((sum: number, item: any) => sum + (MAIN_ITEM_PREMIUMS[item.type] ?? 0), 0);
40	
41	  const mainItemPremium = mainItems
42	    .reduce((sum: number, item: any) => sum + calculateMainItemPremium(item), 0);
43	
44	  const componentCounts = countComponentsByType(items);
45	  const componentPremium = Object.values(componentCounts)
46	    .reduce((sum: number, count: number) => sum + calculateComponentPremium(count), 0);
47	
48	  const firstInsurance = policyBasePremium * 0.1;
49	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
50	  const followUpDiscount = isFollowUp ? policyBasePremium * 0.15 : 0;
51	
52	  return mainItemPremium + componentPremium + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
53	};
