55	export function processScenario(scenario: any): unknown {
56	  let quoteCount = 0;
57	  const results = scenario.steps.map((step: any) => {
58	    if (step.op === "quote") {
59	      const isFollowUp = quoteCount > 0;
60	      quoteCount++;
61	      return { premium: calculateQuotePremium(step.items, scenario.customer, isFollowUp) };
62	    }
63	  });
64	  return { results };
65	}
